// ─────────────────────────────────────────────────────────────────────────
// NODE: "Normalize input"  (Code node, mode: "Run Once for All Items")
// Reads the user's message + IG ids from the Webhook, and any KNOWN field
// values, then builds the rigid scripted system prompt. Persona is fixed:
// always "Rahul" from Outbound Travellers.
//
// COLLECTION ORDER (strict, never deviate):
//   1. destination          → ask "which destination?"
//   2. travel_date          → ask "when are you planning to travel?"
//   3. pax                  → ask "how many people?"
//   4. whatsapp_number      → ask "your WhatsApp number?"
//   5. quick_assistance     → send Yes/No button after phone is captured
//
// BUTTON-CLICK SHORTCUT:
//   If the incoming message is exactly "Yes" or "No" AND we already have
//   whatsapp_number filled AND quick_assistance is still empty, this turn is
//   treated as a button click. We skip the AI Agent and handle it downstream.
//
// MEMORY — production design, 3 layers:
//   1. Simple Memory (memoryBufferWindow) attached to the AI Agent.
//   2. KNOWN FIELDS — merged from the Google Sheet row + ManyChat webhook body.
//   3. NOTES — short one-line summary in the "notes - AI" column.
//
// ⚠️ Webhook payload lives under $json.body — read via $('Webhook').
// ⚠️ The notes column header is literally "notes - AI" (with spaces).
// ⚠️ Strip ManyChat unresolved merge tags (literal double-braces).
// ⚠️ Code node MUST return [{ json: { ... } }].
// NOTE: keep prompts/system_prompt.md in sync with this embedded prompt.
// ─────────────────────────────────────────────────────────────────────────

const wh = $('Webhook').first().json.body || {};
const s = (v) => (v === undefined || v === null ? '' : String(v).trim());
const OB = String.fromCharCode(123) + String.fromCharCode(123);
const CB = String.fromCharCode(125) + String.fromCharCode(125);
const clean = (v) => { const t = s(v); return (t.slice(0, 2) === OB && t.slice(-2) === CB) ? '' : t; };
// Prefer the sheet value; fall back to the value ManyChat passed in the body.
const pick = (a, b) => { const x = clean(a); return x !== '' ? x : clean(b); };

// -- DEDUP LAYER 1: synchronous same-message guard. --
const _sd = $getWorkflowStaticData('global');
_sd.seenMsg = _sd.seenMsg || {};
const _now = Date.now();
for (const _k in _sd.seenMsg) { if (_now - _sd.seenMsg[_k] > 3600000) delete _sd.seenMsg[_k]; }
const _dupKey = s(wh.ig_user_id) + '|' + s(wh.message_text);
if (s(wh.ig_user_id) && s(wh.message_text) && _sd.seenMsg[_dupKey] && (_now - _sd.seenMsg[_dupKey] < 4000)) return [];
if (_dupKey) _sd.seenMsg[_dupKey] = _now;
// Unique per-execution token for the Layer-2 sheet ownership lock (last-writer-wins).
const _msgId = 'L' + _now + '-' + Math.floor(Math.random() * 1000000);

let row = {};
try {
  const inItems = $input.all();
  if (inItems && inItems.length && inItems[0] && inItems[0].json) {
    const j = inItems[0].json;
    if (j && (clean(j.destination) || clean(j.normalized_destination) || clean(j.travel_date) || clean(j.pax) || clean(j.whatsapp_number) || clean(j.quick_assistance) || clean(j['notes - AI']) || clean(j.first_contact_ts) || clean(j.name))) row = j;
  }
} catch (e) { row = {}; }

const userMsg = s(wh.message_text);

const known = {
  destination:           pick(row.destination, wh.destination),
  normalized_destination: pick(row.normalized_destination, wh.normalized_destination),
  travel_date:           pick(row.travel_date, wh.travel_date),
  pax:                   pick(row.pax, wh.pax),
  whatsapp_number:       pick(row.whatsapp_number, wh.whatsapp_number),
  quick_assistance:      pick(row.quick_assistance, wh.quick_assistance),
};

// -- CONVERSATION RESET RULE --
// Start fresh if the user greets us OR if we haven't heard from them in >48 hours.
// Robust IST timestamp parser (handles single-digit hours that Google Sheets may return).
function parseIST(ts) {
  const m = String(ts).trim().match(/^(\d{4})-(\d{1,2})-(\d{1,2})[ T](\d{1,2}):(\d{2}):(\d{2})$/);
  if (!m) return NaN;
  const [, y, mo, d, h, mi, s] = m.map(Number);
  const pad = (n) => String(n).padStart(2, '0');
  return new Date(`${y}-${pad(mo)}-${pad(d)}T${pad(h)}:${pad(mi)}:${pad(s)}+05:30`).getTime();
}

// -- 2-DAY MEMORY RULE --
// Remember everything for 48h since the last message. A returning lead within
// 48h CONTINUES where they left off (a plain "Hi" does NOT restart). After 48h
// idle we forget (fields + memory) and the next message starts from the greeting.
// A brand-new lead has no prior timestamp (hoursSince = Infinity) so they reset
// → greeting, exactly like a >48h returner.
const lastUpdateTs = clean(row.last_update_ts) || clean(row.first_contact_ts);
let hoursSince = Infinity;
if (lastUpdateTs) {
  const lastMs = parseIST(lastUpdateTs);
  if (!isNaN(lastMs)) hoursSince = (_now - lastMs) / (1000 * 60 * 60);
}
// -- SMART RESET RULE (owner 2026-07-03) --
// Under 2h idle: ALWAYS continue. After 2h: a CONNECTED reply (answers the
// pending question, gives a reason for the silence, mentions the trip)
// CONTINUES with full memory; only a pure fresh greeting ("hi", "hello",
// "good morning") starts a NEW conversation. Brand-new leads always start fresh.
const _greetTokens = userMsg.toLowerCase().replace(/[^a-z\s]/g, ' ').trim().split(/\s+/).filter(Boolean);
const GREET_WORDS = ['hi', 'hii', 'hiii', 'hiiii', 'hello', 'helo', 'hellooo', 'hey', 'heyy', 'heyyy', 'hai', 'hlo', 'yo', 'gm', 'gn', 'good', 'morning', 'afternoon', 'evening', 'night', 'namaste', 'vanakkam', 'hola', 'greetings', 'sir', 'madam', 'mam', 'team', 'there', 'bro', 'ji', 'anna', 'dear', 'all'];
const isPureGreeting = _greetTokens.length > 0 && _greetTokens.length <= 4 && _greetTokens.every((t) => GREET_WORDS.indexOf(t) !== -1);
const resetConversation = (hoursSince === Infinity) || (hoursSince >= 2 && isPureGreeting);

if (resetConversation) {
  known.destination = '';
  known.normalized_destination = '';
  known.travel_date = '';
  known.pax = '';
  known.whatsapp_number = '';
  known.quick_assistance = '';
}
// Overlay: a Yes/No just handled by Button handler may not be visible in the
// sheet yet (read lag) — trust the in-workflow stamp so we never re-ask.
const _sdQA = $getWorkflowStaticData('global');
_sdQA.qaDone = _sdQA.qaDone || {};
for (const _q in _sdQA.qaDone) { if (_now - (_sdQA.qaDone[_q].ts || 0) > 72 * 3600 * 1000) delete _sdQA.qaDone[_q]; }
const _qaHit = _sdQA.qaDone[s(wh.ig_user_id)];
if (resetConversation) { delete _sdQA.qaDone[s(wh.ig_user_id)]; if (_sdQA.neSalt) { delete _sdQA.neSalt[s(wh.ig_user_id)]; } }
else if (_qaHit && !known.quick_assistance) { known.quick_assistance = _qaHit.v; }

const knownJson = JSON.stringify(known);

const hasDestination = !!(known.destination || known.normalized_destination);
const hasTravelDate = !!known.travel_date;
const hasPax = !!known.pax;
const hasPhone = !!known.whatsapp_number;
const hasQuickAssist = !!known.quick_assistance;

let existingFirstContact = clean(row.first_contact_ts);
let existingNotes = pick(row['notes - AI'], wh.notes);

if (resetConversation) {
  existingFirstContact = '';
  existingNotes = '';
}

// -- CONVERSATION EPOCH (memory-session isolation) --
// first_contact_ts doubles as the conversation epoch. It is stable for the life
// of a conversation but rotates whenever we reset (>48h idle, so existingFirstContact
// was just cleared). The AI's Simple Memory is keyed by this epoch, so a reset
// starts a FRESH memory session — that is what makes the bot "forget after 2 days".
const nowISTstr = new Date(_now + 5.5 * 60 * 60 * 1000).toISOString().replace('T', ' ').slice(0, 19);
const convFirstContact = existingFirstContact || nowISTstr;
// Key the memory session off the PARSED epoch (ms), not the raw string — Google Sheets
// reformats the saved timestamp on read-back (e.g. strips the leading zero from the hour),
// which would otherwise split one conversation across two memory buckets.
const _epochMs = parseIST(convFirstContact);
const _neSalt = (_sdQA.neSalt && _sdQA.neSalt[s(wh.ig_user_id)]) || '';
const sessionKey = s(wh.ig_user_id) + '|' + (isNaN(_epochMs) ? convFirstContact : _epochMs) + (_neSalt ? '|ne' + _neSalt : '');

const notesBlock = existingNotes ? existingNotes : '(none yet — fresh conversation)';
// "We've already started this conversation" — true once a row exists within the
// 48h window (so the greeting fires exactly once per conversation, never twice).
const priorChat = !resetConversation && (!!existingFirstContact || hasDestination || hasTravelDate || hasPax || hasPhone || hasQuickAssist || !!existingNotes);

// Account display name from ManyChat; fallback to the name already saved in
// the sheet row so a saved name is never downgraded to blank.
const igFullName = clean(wh.ig_fullname) || pick(row.name, '');
const igUsername = s(wh.ig_username);
const channel = (clean(wh.channel) || 'instagram').toLowerCase();
const channelLabel = channel === 'instagram' ? 'instagram' : 'facebook';

// Detect a Yes/No answer at the quick-assistance step (FUZZY — 2026-07-06).
// Real lead on .in typed "Yess" → exact-match list missed it → QA re-ask loop.
// Now: tokenize, collapse stretched letters (yesss→yes, nooo→no), match per
// token so "yes i need help" works, and arm the detector ONLY when the QA
// question is actually pending (all lead fields captured).
const _qaTok = userMsg.toLowerCase().replace(/[^a-z\s]/g, ' ').split(/\s+/).filter(Boolean).map((t) => t.replace(/(.)\1+/g, '$1'));
const _yesSet = ['yes', 'yeah', 'yea', 'yep', 'yup', 'ya', 'y', 's', 'sure', 'ok', 'okay', 'okey', 'okie', 'k', 'need', 'needed', 'want', 'please', 'pls', 'plz'];
const _noSet = ['no', 'nope', 'nah', 'na', 'not', 'dont', 'don', 'dnt'];
const _hasNoTok = _qaTok.some((t) => _noSet.indexOf(t) !== -1);
const _hasYesTok = _qaTok.some((t) => _noSet.indexOf(t) === -1 && _yesSet.indexOf(t) !== -1);
const _qaPending = hasDestination && hasTravelDate && hasPax && hasPhone && !hasQuickAssist;
const isButtonClick = _qaPending && (_hasNoTok || _hasYesTok);
const buttonValue = isButtonClick ? (_hasNoTok ? 'no' : 'yes') : '';

const WA = '+91 9597959728';
const WA_LINK = 'https://wa.me/919597959728';

// ── EXTRACTOR-ONLY PROMPT ────────────────────────────────────────────────
// The AI does NOT chat and does NOT write replies. It ONLY pulls field values
// out of the user's message and normalizes the destination. The conversation
// wording is 100% scripted downstream in "Parse + validate" — this keeps the
// agent on rails (no improvising, no extra questions, no off-script chatter).
const systemPrompt = `You are a silent data-extraction engine for Outbound Travellers, a travel agency. You do NOT chat. You NEVER write a message to the user. You ONLY read the user's latest message together with the KNOWN FIELDS already collected, and return updated field values as JSON.

## FIELDS YOU EXTRACT (only these four — capture any the user volunteers)
1. destination        — the place they want to travel to.
2. travel_date        — when they plan to travel. Free text is fine: "15th August", "next month", "flexible".
3. pax                — number of people travelling. Convert clear phrases to a number ("me and my wife" → "2", "just me" → "1"); otherwise keep the short phrase.
4. whatsapp_number    — their contact / WhatsApp number, exactly as typed (validation happens downstream).

## HARD RULES
- Extract ONLY what the user actually provided in THIS message or already-known values. NEVER invent, guess, or assume a value. If the message has nothing for a field, keep the KNOWN value (or empty).
- If the user gives several fields in one message, capture ALL of them.
- You do NOT decide what to ask next. You do NOT greet, acknowledge, or reply. Output JSON only.
- IGNORE anything outside the four fields (budget, name, hotel, flight, itinerary). Do not store them.
- Field extraction is INDEPENDENT of intent: ALWAYS populate destination/travel_date/pax/whatsapp_number with any value the user states, EVEN IF the message is a question, a price/package/'send details' request, a comparison ("X or Y" -- capture the raw options as destination), or code-mixed Tamil/Hindi/Malayalam in Latin script (Tanglish/Hinglish/Manglish -- e.g. "send pannunga"=please send, "kuda"=also, "venum"=want, "illa/venam"=no). If your own notes mention a value, that value MUST appear in the matching field.

## DESTINATION NORMALIZATION (important)
Always also return "normalized_destination" = the correct, canonical destination name — fix misspellings and resolve partial/loose names to the proper place:
- "Jammu" / "kashmir" / "i want to explore kashmir" / "kashmeer" → "Jammu and Kashmir"
- "balli" / "bali island" / "bally" → "Bali"
- "goa beach" / "gova" → "Goa"
- "kerela" / "kerla" → "Kerala"
- "andaman" / "andmaan" → "Andaman and Nicobar Islands"
If you cannot recognize a real place, set "destination" to what they typed and leave "normalized_destination" empty.

## CONSULTATION QUESTIONS (flag only — do NOT answer them)
If the user's message is mainly a question asking for advice, opinions, recommendations, prices, packages, weather or best season, hotels, itinerary, visa, or any comparison (e.g. "Is Munnar better in the monsoon?", "Is Kashmir good this month?"), set "consult_question": true. Still capture any fields they volunteered in the same message. Greetings, acknowledgments ("ok", "okay", "thanks", "hmm"), refusals, and plain statements are NOT consultation questions — for those set it false.

## REFUSAL / NOT INTERESTED (flag only)
Set "user_refused": true ONLY when the user declines to share their contact number or clearly wants to stop (e.g. "I don't have WhatsApp", "I won't share my number", "not interested", "stop messaging"). A normal answer, greeting, or question is NOT a refusal. Otherwise false.

## NOTES
Return "notes" = one short English line summarizing what is known so far (max ~20 words).

## OUTPUT — return ONLY this JSON. No markdown, no code fences, no preamble, no reply text.
{"fields":{"destination":"","normalized_destination":"","travel_date":"","pax":"","whatsapp_number":""},"notes":"<one short line>","status":"new | in_progress | qualified","consult_question":false,"user_refused":false}

KNOWN FIELDS: ${knownJson}`;

return [{
  json: {
    ig_user_id:                s(wh.ig_user_id),
    ig_username:               igUsername,
    ig_fullname:               igFullName,
    user_message:              userMsg,
    known_fields:              known,
    known_fields_json:         knownJson,
    prior_chat:                priorChat,
    existing_first_contact_ts: existingFirstContact,
    conv_first_contact:        convFirstContact,
    session_key:               sessionKey,
    existing_notes:            existingNotes,
    system_prompt:             systemPrompt,
    msg_id:                    _msgId,
    channel:                   channel,
    channel_label:             channelLabel,
    is_button_click:           isButtonClick,
    button_value:              buttonValue,
  },
}];

// ─────────────────────────────────────────────────────────────────────────
// NODE: "Parse + validate"  (Code node, "Run Once for All Items")
// Parses the AI Agent JSON output for the new Rahul scripted flow.
// Validates the WhatsApp number, merges fields over known ones, computes
// status, and keeps the running one-line notes summary.
// ⚠️ Code node MUST return [{ json: { ... } }].
// ─────────────────────────────────────────────────────────────────────────

// Core 4 fields. A lead is "qualified" once all four are captured.
const QUALIFY = ['destination', 'travel_date', 'pax', 'whatsapp_number'];
const FIELDS = ['destination', 'normalized_destination', 'travel_date', 'pax', 'whatsapp_number'];

// 1. Grab the raw LLM text (AI Agent → $json.output; other shapes as fallback).
const up = $json || {};
let raw = '';
if (typeof up.output === 'string') raw = up.output;
else if (up.output && typeof up.output === 'object') raw = JSON.stringify(up.output);
else if (up.message && typeof up.message.content === 'string') raw = up.message.content;
else if (up.choices && up.choices[0] && up.choices[0].message) raw = up.choices[0].message.content;
else if (typeof up.text === 'string') raw = up.text;
else if (typeof up.content === 'string') raw = up.content;

// 2. Strip stray ```json fences, parse safely.
let parsed = null;
try {
  const cleaned = String(raw).replace(/```json/gi, '').replace(/```/g, '').trim();
  if (cleaned) parsed = JSON.parse(cleaned);
} catch (e) { parsed = null; }

// 3. Safe fallback — malformed JSON / AI failure must not crash the flow.
if (!parsed || typeof parsed !== 'object') {
  parsed = {
    reply: 'Thanks so much for messaging Outbound Travellers! 😊 Our team will get back to you very shortly.',
    intent: 'travel_lead',
    fields: {},
    ask_quick_assistance: false,
    notes: '',
    status: 'in_progress',
  };
}

// 4. Validate intent.
const VALID = ['travel_lead', 'office_info', 'career', 'customer_query'];
let intent = (parsed.intent && String(parsed.intent).trim()) || 'travel_lead';
if (VALID.indexOf(intent) === -1) intent = 'travel_lead';

const llmFields = (parsed.fields && typeof parsed.fields === 'object') ? parsed.fields : {};
const norm = $('Normalize input').first().json;
const knownF = norm.known_fields || {};

const OB = String.fromCharCode(123) + String.fromCharCode(123);
const CB = String.fromCharCode(125) + String.fromCharCode(125);
const strip = (v) => { const t = (v === undefined || v === null) ? '' : String(v).trim(); return (t.slice(0, 2) === OB && t.slice(-2) === CB) ? '' : t; };

function cleanPhone(v) {
  if (!v) return '';
  let d = String(v).replace(/\D/g, '');
  // Indian 10-digit mobile (optionally written with 91 / 0 / +91) -> '+91 xxxxx xxxxx'
  let in10 = d;
  if (in10.length === 12 && in10.startsWith('91')) in10 = in10.slice(2);
  else if (in10.length === 11 && in10.startsWith('0')) in10 = in10.slice(1);
  if (in10.length === 10 && /^[6-9]/.test(in10)) return '+91 ' + in10.slice(0, 5) + ' ' + in10.slice(5);
  // International number (came with its own country code / + sign) -> keep it, with the +
  const hadPlus = String(v).trim().charAt(0) === '+';
  if (d.startsWith('00')) d = d.slice(2);
  if (hadPlus || (d.length >= 11 && d.length <= 15)) return '+' + d;
  return '';
}

// 5. Merge. For non-travel intents, don't let the LLM invent lead data.
const takeLLM = (intent === 'travel_lead');
const merged = {};
for (const f of FIELDS) {
  const nv = takeLLM ? strip(llmFields[f]) : '';
  const kv = strip(knownF[f]);
  merged[f] = nv !== '' ? nv : kv;
}
merged.whatsapp_number = cleanPhone(merged.whatsapp_number);

// If the AI returned a destination but no normalized_destination, fall back to destination.
if (!merged.normalized_destination && merged.destination) {
  merged.normalized_destination = merged.destination;
}

// -- NEW-ENQUIRY DETECTION (comment-led re-entry) --
// A lead who already answered quick assistance and now names a DIFFERENT
// destination is starting a fresh enquiry (they commented on another
// destination video). Keep their phone; restart the trip details warmly.
const _oldDest = (strip(knownF.normalized_destination) || strip(knownF.destination)).toLowerCase();
const _newDestL = String(merged.normalized_destination || merged.destination || '').toLowerCase();
const newEnquiry = !!_oldDest && !!_newDestL && _newDestL !== _oldDest && !!strip(knownF.quick_assistance);
if (newEnquiry) {
  // The extractor echoes KNOWN values, so keep month/pax only when THIS message
  // gave a genuinely new value; otherwise re-collect for the new trip.
  const _lfDate = takeLLM ? strip(llmFields.travel_date) : '';
  merged.travel_date = (_lfDate && _lfDate !== strip(knownF.travel_date)) ? _lfDate : '';
  const _lfPax = takeLLM ? strip(llmFields.pax) : '';
  merged.pax = (_lfPax && _lfPax !== strip(knownF.pax)) ? _lfPax : '';
  const _sdNE = $getWorkflowStaticData('global');
  if (_sdNE.qaDone) { delete _sdNE.qaDone[String(norm.ig_user_id)]; }
  if (_sdNE.qaAsk) { delete _sdNE.qaAsk[String(norm.ig_user_id) + '|' + String(norm.conv_first_contact || '')]; }
  _sdNE.neSalt = _sdNE.neSalt || {};
  _sdNE.neSalt[String(norm.ig_user_id)] = Date.now();
}

// -- DETERMINISTIC FIELD BACKSTOP (2026-07-08 audit) -- the AI extractor drops a
// field when its value sits inside a question / comparison / package request or
// code-mixed (Tanglish) text, which made the bot re-ask something already
// answered. Regex-scan the raw message and fill any EMPTY core field. (Destination
// stays AI-only -- too open to regex; handled by the extractor prompt.)
const _um = String(norm.user_message || '');
const _umL = _um.toLowerCase();
if (!merged.travel_date) {
  const _mon = _umL.match(/\b(jan(uary)?|feb(ruary)?|mar(ch)?|apr(il)?|may|jun(e)?|jul(y)?|aug(ust)?|sep(tember|t)?|oct(ober)?|nov(ember)?|dec(ember)?)\b/);
  if (_mon) merged.travel_date = _mon[0].charAt(0).toUpperCase() + _mon[0].slice(1);
  else { const _rel = _um.match(/next month|this month|next week|coming month|month end|year end|flexible|any ?time/i); if (_rel) merged.travel_date = _rel[0]; }
}
if (!merged.pax) {
  const _pn = _um.match(/(\d{1,3})\s*(?:people|persons?|pax|adults?|members?|of us|travell?ers?|heads?|nos)\b/i) || _umL.match(/\bfor\s+(\d{1,3})\b/) || _umL.match(/\bwe(?:'?re| are)\s+(\d{1,3})\b/);
  if (_pn) merged.pax = _pn[1];
  else if (/\bhoneymoon\b|\bcouple\b|\bme and my (?:wife|husband|partner|hubby)\b|\bwe two\b|\bboth of us\b|\bmy spouse\b/.test(_umL)) merged.pax = '2';
  else if (/\bsolo\b|\bjust me\b|\bmyself\b|\balone\b|\bonly me\b/.test(_umL)) merged.pax = '1';
  else { const _fam = _umL.match(/family of (\d{1,2})/); if (_fam) merged.pax = _fam[1]; }
}
if (!merged.whatsapp_number) {
  const _digits = _um.replace(/[^0-9]/g, ' ');
  const _ph = _digits.match(/\b([6-9]\d{9})\b/) || _digits.match(/\b91\s*([6-9]\d{9})\b/);
  if (_ph && !/^(\d)\1{9}$/.test(_ph[1])) merged.whatsapp_number = '+91 ' + _ph[1].slice(0, 5) + ' ' + _ph[1].slice(5);
}

// -- FIELD MEMORY CACHE (2026-07-08) -- the Google-Sheets lookup can return a
// stale/empty row on a rapid follow-up (esp. right after a save), which would
// blank a field the customer already gave and make the bot re-ask it. Keep a
// short-lived (48h) per-user cache of the last non-empty core-field values and
// fall back to it. Gated on prior_chat (a >48h reset still forgets) and
// !newEnquiry (a new-destination enquiry still re-collects for the new trip).
const _sdF = $getWorkflowStaticData('global');
_sdF.fieldCache = _sdF.fieldCache || {};
const _fcKey = String(norm.ig_user_id);
const _nowF = Date.now();
for (const _k in _sdF.fieldCache) { if (_nowF - ((_sdF.fieldCache[_k] || {})._ts || 0) > 48 * 3600 * 1000) delete _sdF.fieldCache[_k]; }
const _fc = _sdF.fieldCache[_fcKey] || {};
const _CF = ['destination', 'normalized_destination', 'travel_date', 'pax', 'whatsapp_number'];
if (norm.prior_chat === true && !newEnquiry) {
  for (const f of _CF) { if ((!merged[f] || merged[f] === '') && _fc[f]) merged[f] = _fc[f]; }
}
const _fcNew = { _ts: _nowF };
for (const f of _CF) { if (merged[f] && merged[f] !== '') _fcNew[f] = merged[f]; }
_sdF.fieldCache[_fcKey] = _fcNew;

// 6. Notes (running summary). Take the LLM's fresh summary when it gave one.
const newNotes = strip(parsed.notes);
const prevNotes = strip(norm.existing_notes);
const notes = newNotes !== '' ? newNotes : prevNotes;

// 7. Status: qualified once the core 4 are filled; in_progress if anything captured.
const qualified = QUALIFY.every((f) => merged[f] && merged[f] !== '');
const anyFilled = FIELDS.some((f) => merged[f] && merged[f] !== '');
const status = qualified ? 'qualified' : (anyFilled ? 'in_progress' : 'new');

// 8. DETERMINISTIC SCRIPTED REPLY — the AI only extracts fields; every line the
//    customer sees is fixed here, so the agent cannot improvise or go off-script.
//    Pick the message for the next missing field, in strict order:
//    destination → travel_date → pax → whatsapp_number → quick-assistance.
const hasDest  = !!(merged.destination || merged.normalized_destination);
const hasDate  = !!merged.travel_date;
const hasPaxF  = !!merged.pax;
const hasPhone = !!(merged.whatsapp_number && merged.whatsapp_number !== '');
const priorChat = norm.prior_chat === true;

// Ask quick-assistance once all four are captured and it isn't already answered.
const askQuickAssist = hasDest && hasDate && hasPaxF && hasPhone && (newEnquiry || !strip(knownF.quick_assistance));

// Deterministic consult backstop (2026-07-08 audit): indirect questions
// ("more info", "package for X", "B2B rates", "send details", "is it safe")
// slipped past the AI flag and got answered with the next field. Force the
// expert-deflection when the message clearly asks for advice/price/details.
const _consultRe = /\b(price|cost|rate|rates|charges?|quot|discount|b2b|packages?|itinerary|inclusion|visa|passport|best (?:time|season|month)|which (?:is )?better|per head|per person|land package)\b|\bis it safe\b|\bsend (?:me )?(?:the )?(?:details|info|itinerary|package|quote)\b|\bmore (?:info|details)\b|\b(?:call|contact|reach) me\b|\bwhen (?:will|can) (?:you|u) (?:call|contact)\b/i;
const consultQ = (parsed.consult_question === true) || _consultRe.test(String(norm.user_message || ''));
const userRefused = parsed.user_refused === true;
const CONSULT_INTRO = (norm.prior_chat === true) ? '' : 'Hi, this is Rahul from Outbound Travellers. ';
let replyText;
if (userRefused) {
  replyText = "No problem at all! Thank you for your time. If you ever plan a trip, our team is just a message away. Have a great day! \ud83d\ude0a";
} else if (consultQ && !hasPhone) {
  replyText = CONSULT_INTRO + "I completely understand! I'm not able to share those details here. Please share your WhatsApp number \u2014 one of our travel experts will personally help you with this on WhatsApp.";
} else if (consultQ) {
  replyText = CONSULT_INTRO + "I completely understand! I'm not able to share those details here, but one of our travel experts will contact you on WhatsApp and help you with this.";
} else if (newEnquiry) {
  const _dn = merged.normalized_destination || merged.destination;
  replyText = _dn + ' is a great choice too! ' + (!merged.travel_date
    ? 'Which month are you planning to travel?'
    : (!merged.pax ? 'May I know the number of people travelling?'
    : 'Thanks for your co-operation. Do you need quick assistance? Please reply Yes or No.'));
} else if (askQuickAssist) {
  replyText = 'Thanks for your co-operation. Do you need quick assistance? Please reply Yes or No.';
} else if (!hasDest) {
  // First contact gets the full intro; a continuing chat just re-asks for destination.
  replyText = priorChat
    ? 'May I know which destination you are looking for?'
    : 'Hi, this is Rahul from Outbound Travellers. May I know which destination you are looking for?';
} else if (!hasDate) {
  replyText = 'Great choice! Which month are you planning to travel?';
} else if (!hasPaxF) {
  replyText = 'Great. May I know the number of people travelling?';
} else if (!hasPhone) {
  replyText = 'Please share your WhatsApp number:';
} else {
  // All four captured and quick-assistance already answered.
  const _ack = String(norm.user_message || '').toLowerCase().replace(/[^a-z]/g, '');
  const ACKS = ['ok', 'okay', 'okk', 'okie', 'okey', 'k', 'kk', 'hm', 'hmm', 'thanks', 'thankyou', 'thanku', 'thx', 'tq', 'great', 'nice', 'good', 'super', 'fine', 'cool', 'done', 'sure', 'welcome'];
  if (ACKS.indexOf(_ack) !== -1 || _ack === '') {
    replyText = '';  // bare acknowledgment after completion -> stay silent like a human
  } else {
    replyText = 'Thank you! Our travel consultant will get back to you shortly.';
  }
}

// -- QA RE-ASK CAP (2026-07-07) -- the quick-assistance question is asked at
// most TWICE per conversation. On what would be the 3rd ask we close warmly
// and mark quick_assistance = 'no_response' so it can never loop again (real
// leads were spammed when their replies carried no yes/no signal).
let qaClosed = false;
if (replyText && replyText.indexOf('Do you need quick assistance') !== -1) {
  const _sdC = $getWorkflowStaticData('global');
  _sdC.qaAsk = _sdC.qaAsk || {};
  const _nowC = Date.now();
  for (const _k in _sdC.qaAsk) { if (_nowC - (_sdC.qaAsk[_k].ts || 0) > 72 * 3600 * 1000) delete _sdC.qaAsk[_k]; }
  const _cKey = String(norm.ig_user_id) + '|' + String(norm.conv_first_contact || '');
  const _c = (_sdC.qaAsk[_cKey] && _sdC.qaAsk[_cKey].c) || 0;
  if (_c >= 2) {
    qaClosed = true;
    replyText = 'No problem! Our travel consultant will reach out to you soon. 😊';
  } else {
    _sdC.qaAsk[_cKey] = { c: _c + 1, ts: _nowC };
  }
}

// Fresh-conversation intro: comment-keyword entries often carry the destination
// as the very first message — still introduce Rahul once.
if (norm.prior_chat !== true && replyText && replyText.indexOf('Hi, this is Rahul') === -1 && !userRefused) {
  replyText = 'Hi, this is Rahul from Outbound Travellers! ' + replyText;
}

// -- SAME-REPLY SUPPRESSION (2026-07-08) -- if this exact reply text already
// went to this user in the last 10 minutes, send nothing instead of repeating
// verbatim (double-texting customers used to get the same scripted question
// twice in a row -> "double reply" complaints; post-done thank-you spammed too).
const _sdR = $getWorkflowStaticData('global');
_sdR.lastReply = _sdR.lastReply || {};
const _nowR = Date.now();
for (const _k in _sdR.lastReply) { if (_nowR - (_sdR.lastReply[_k].ts || 0) > 3600000) delete _sdR.lastReply[_k]; }
const _lrKey = String(norm.ig_user_id);
const _lr = _sdR.lastReply[_lrKey];
const _rkey = String(replyText || '').replace(/^Hi, this is Rahul from Outbound Travellers! /, '').trim();
if (replyText && _lr && _lr.text === _rkey && (_nowR - _lr.ts) < 10 * 60 * 1000) {
  replyText = '';
} else if (replyText) {
  _sdR.lastReply[_lrKey] = { text: _rkey, ts: _nowR };
}

// 9. CRM push is handled by the Button handler on a Yes click (not on the phone turn).
const CRM_FIELDS = ['destination', 'travel_date', 'pax', 'whatsapp_number'];
const crmReady = CRM_FIELDS.every((f) => merged[f] && merged[f] !== '');
const crmWasReady = CRM_FIELDS.every((f) => strip(knownF[f]) !== '');
const crmPush = crmReady && (!crmWasReady || newEnquiry); // push ONCE per enquiry (a new-destination enquiry pushes again)

// 10. Timestamps. Use the conversation epoch from Normalize as first_contact_ts so the
//     saved value matches the memory session key (both rotate together on a >48h reset).
const nowIST = new Date(Date.now() + 5.5 * 60 * 60 * 1000).toISOString().replace('T', ' ').slice(0, 19);
const firstContact = (norm.conv_first_contact && String(norm.conv_first_contact).trim())
  || (norm.existing_first_contact_ts && String(norm.existing_first_contact_ts).trim())
  || nowIST;

return [{
  json: {
    ig_user_id:          norm.ig_user_id,
    ig_username:         norm.ig_username,
    full_name:           strip(norm.ig_fullname),
    reply:               replyText,
    intent,
    is_lead:             !!(merged.whatsapp_number && merged.whatsapp_number !== ''),
    destination:         merged.destination,
    normalized_destination: merged.normalized_destination,
    travel_date:         merged.travel_date,
    pax:                 merged.pax,
    whatsapp_number:     merged.whatsapp_number,
    quick_assistance:    qaClosed ? 'no_response' : (newEnquiry ? '' : strip(knownF.quick_assistance)),
    ask_quick_assistance: askQuickAssist && !qaClosed,
    notes,
    status,
    crm_push:            crmPush,
    first_contact_ts:    firstContact,
    last_update_ts:      nowIST,
  },
}];

